  ('social-worker-moex-02453', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '杭廷頓舞蹈症（Huntington’s chorea）是一種染色體違常的病症。有關該症狀的敘述，下列何者錯誤？', '["屬於顯性基因違常", "特徵是漸進式肌肉痙攣", "最後會演變至失智退化", "後代發生率為70%～75%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "792bab7a1f14", "answer_pdf_sha1": "e73a95e1d0e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02454', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關典型健康老人的敘述，下列何者錯誤？', '["關切生命與生活的傳承", "傾向於活在當下", "想要發揮老人的功能，分享累積的知識", "對熟悉事務的依附，但創造力與好奇心會降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "792bab7a1f14", "answer_pdf_sha1": "e73a95e1d0e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02455', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '新近研究顯示，由於人類年齡的延長趨勢，成年晚期的階段有必要加以細分。依據Hartford的觀點， 老年階段可區分為青老年、中老年、老老年；其中，中老年的年齡範圍為下列何者？', '["65～74歲", "75～84歲", "85～90歲", "90歲以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "792bab7a1f14", "answer_pdf_sha1": "e73a95e1d0e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02456', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作人員在評估案主社會功能的心理層面時，必須能分辨心情（mood）與感受（affect）的差異。 所謂「感受」是指下列何者？', '["比較持久的情緒", "當下的情緒", "已經發生過的情緒", "一種自我激勵的意義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "792bab7a1f14", "answer_pdf_sha1": "e73a95e1d0e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
